+    /// Bitwise AND: self & other
+    pub fn bitAnd(self: Self, other: Self, allocator: Allocator) !Self {
+        switch (self) {
+            .small => |a| switch (other) {
+                .small => |b| {
+                    return .{ .small = a & b };
+                },
+                .big => |b_big| {
